/**
 * Profiles Service — User and freelancer profile queries
 */
import { supabase, uploadFile } from '@/lib/supabase';
import { sanitizeFreelancerProfileData } from '@/lib/schemaValidation';

// --- READ ---

// getProfileById: reads from the public_profiles VIEW (safe columns only).
// Accessible to anon + authenticated via view-level GRANT.
// Does NOT expose: email, phone, is_admin, account_status, cin_submitted.
export async function getProfileById(userId: string) {
    return supabase
        .from('public_profiles')
        .select('*')
        .eq('id', userId)
        .single();
}

// Full own-profile read — only safe to call when userId === auth.uid().
// Reads the base table (all columns). Protected by profiles_select_own RLS.
export async function getOwnProfile(userId: string) {
    return supabase.from('profiles').select('*').eq('id', userId).single();
}

export async function getFreelancerProfile(userId: string) {
    return supabase.from('freelancer_profiles').select('*').eq('id', userId).single();
}

export async function getFreelancerWithProfile(userId: string) {
    return supabase
        .from('profiles')
        .select(`*, freelancer_profiles(*), portfolio_items(*)`)
        .limit(20, { foreignTable: 'portfolio_items' })
        .eq('id', userId)
        .single();
}

export async function getFreelancers(filters: {
    search?: string;
    skills?: string[];
    availability?: string;
    minRate?: number;
    maxRate?: number;
    locations?: string[];
    excludeId?: string;   // exclude the current user from their own search results
} = {}, page = 1, pageSize = 20) {
    // Use authenticated client — ensures RLS policies allow reading freelancer_profiles
    // Query the public_profiles view — safe columns only, anon-readable.
    let query = supabase
        .from('public_profiles')
        .select(`
            id,
            full_name,
            avatar_url,
            location,
            user_type,
            freelancer_profiles!inner (
                id,
                title,
                hourly_rate,
                availability,
                skills,
                jobs_completed,
                success_rate,
                cin_verified
            )
        `, { count: 'exact' })
        .in('user_type', ['freelancer', 'both']);

    if (filters.search) {
        // Strip out characters that could break parsing
        const safeSearch = filters.search.replace(/[,\"_%]/g, ' ').trim();
        if (safeSearch) {
            query = query.or(`full_name.ilike.%${safeSearch}%,freelancer_profiles.title.ilike.%${safeSearch}%`);
        }
    }

    if (filters.availability && filters.availability !== 'any') {
        query = query.eq('freelancer_profiles.availability', filters.availability);
    }

    if (filters.minRate !== undefined) {
        query = query.gte('freelancer_profiles.hourly_rate', filters.minRate);
    }

    if (filters.maxRate !== undefined) {
        query = query.lte('freelancer_profiles.hourly_rate', filters.maxRate);
    }

    if (filters.skills && filters.skills.length > 0) {
        // Assuming skills is a JSONb or text array column
        // use filter by containing elements. PostgREST allows .cs. for contains.
        query = query.contains('freelancer_profiles.skills', filters.skills);
    }

    if (filters.locations && filters.locations.length > 0) {
        query = query.in('location', filters.locations);
    }

    // Exclude the current user so a freelancer does not see themselves in results.
    if (filters.excludeId) {
        query = query.neq('id', filters.excludeId);
    }

    const from = (page - 1) * pageSize;
    query = query.range(from, from + pageSize - 1);

    return query;
}

// --- WRITE ---

export async function updateProfile(userId: string, data: Record<string, unknown>) {
    return supabase
        .from('profiles')
        .update({ ...data, updated_at: new Date().toISOString() })
        .eq('id', userId);
}

export async function updateFreelancerProfile(userId: string, data: Record<string, unknown>) {
    const safeData = sanitizeFreelancerProfileData(data);
    return supabase
        .from('freelancer_profiles')
        .upsert({ id: userId, ...safeData, updated_at: new Date().toISOString() }, { onConflict: 'id' });
}

export async function uploadAvatar(userId: string, file: File) {
    const ext = file.name.split('.').pop();
    const path = `${userId}/avatar-${Date.now()}.${ext}`;
    return uploadFile('avatars', path, file);
}

// --- FAVORITES ---

export async function getFavoriteStatus(userId: string, jobId: string) {
    return supabase
        .from('favorites')
        .select('id')
        .eq('user_id', userId)
        .eq('job_id', jobId)
        .maybeSingle();
}

export async function toggleFavorite(userId: string, jobId: string, isSaved: boolean) {
    if (isSaved) {
        return supabase.from('favorites').delete().eq('user_id', userId).eq('job_id', jobId);
    }
    return supabase.from('favorites').insert({ user_id: userId, job_id: jobId });
}

export async function getSavedJobs(userId: string) {
    return supabase
        .from('favorites')
        .select('job_id, jobs(*)')
        .eq('user_id', userId)
        .order('created_at', { ascending: false })
        .not('job_id', 'is', null);
}

// --- REVIEWS ---

export async function getReviewsByUser(userId: string) {
    return supabase
        .from('reviews')
        .select('*')
        .eq('reviewee_id', userId)
        .order('created_at', { ascending: false });
}

export async function getClientStats(clientId: string) {
    const { data, error } = await supabase.rpc('get_client_stats_v2', { p_client_id: clientId });

    if (error) {
        return { totalJobs: 0, totalSpent: 0, rating: 0 };
    }

    const stats = (data as any)?.[0] || {};
    return {
        totalJobs: stats.job_count || 0,
        totalSpent: Number(stats.total_spent) || 0,
        rating: Number(stats.avg_rating) || 0,
    };
}

/**
 * Supabase Edge Function: Flouci Payment Verification
 *
 * SECURITY:
 * - Requires authenticated user
 * - Verifies caller is the contract's client before completing payment
 * - CORS restricted to production domain
 * - APP_SECRET stays server-side
 */
import { serve } from 'https://deno.land/std@0.168.0/http/server.ts'
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2'

async function logPaymentEvent(supabaseClient: any, payload: {
    user_id: string;
    event_type: string;
    amount: number;
    flouci_session_id?: string;
    contract_id?: string;
    wallet_id?: string;
    status: string;
    metadata?: Record<string, unknown>;
}) {
    try {
        await supabaseClient.from('payment_audit_log').insert({
            ...payload,
            currency: 'TND',
            metadata: payload.metadata ?? {},
        });
    } catch (err) {
        // Never let audit logging crash the payment flow
        console.error('[audit_log] failed to write:', err);
    }
}

const ALLOWED_ORIGIN = Deno.env.get('ALLOWED_ORIGIN') || 'https://khedma.tn'

const corsHeaders = {
    'Access-Control-Allow-Origin': ALLOWED_ORIGIN,
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
}

const FLOUCI_API_URL = Deno.env.get('FLOUCI_API_URL') || 'https://developers.flouci.com/api'
const APP_TOKEN = Deno.env.get('FLOUCI_APP_TOKEN')!
const APP_SECRET = Deno.env.get('FLOUCI_APP_SECRET')!

serve(async (req: Request) => {
    // Handle CORS preflight
    if (req.method === 'OPTIONS') {
        return new Response('ok', { headers: corsHeaders })
    }

    try {
        // --- AUTH CHECK ---
        const supabase = createClient(
            Deno.env.get('SUPABASE_URL')!,
            Deno.env.get('SUPABASE_ANON_KEY')!,
            {
                global: {
                    headers: { Authorization: req.headers.get('Authorization')! }
                }
            }
        )

        const { data: { user }, error: authError } = await supabase.auth.getUser()
        if (authError || !user) {
            console.error('[Flouci Edge] Auth error:', authError)
            return new Response(
                JSON.stringify({ error: 'Unauthorized', details: 'You must be logged in to verify a payment' }),
                { status: 401, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
            )
        }

        // --- INPUT VALIDATION ---
        const { payment_id, complete_payment, transaction_id, contract_id, freelancer_id, amount } = await req.json()

        if (!payment_id || typeof payment_id !== 'string') {
            return new Response(
                JSON.stringify({ error: 'payment_id is required and must be a string' }),
                { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
            )
        }

        console.log('[Flouci Edge] Verifying payment:', payment_id, 'for user:', user.id)

        // --- VERIFY WITH FLOUCI ---
        const response = await fetch(`${FLOUCI_API_URL}/verify_payment/${payment_id}`, {
            method: 'GET',
            headers: {
                'apppublic': APP_TOKEN,
                'appsecret': APP_SECRET,
            },
        })

        if (!response.ok) {
            console.error('[Flouci Edge] Verification API error:', response.status)
            return new Response(
                JSON.stringify({ error: 'Payment verification failed', status: response.status }),
                { status: 502, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
            )
        }

        const data = await response.json()
        console.log('[Flouci Edge] Verification result:', JSON.stringify(data))

        const verificationResult = {
            status: data.result?.status || 'FAILED',
            payment_id: payment_id,
            amount: data.result?.amount || 0,
            developer_tracking_id: data.result?.developer_tracking_id,
            created_at: data.result?.created_at || new Date().toISOString(),
        }

        // --- ATOMIC PAYMENT COMPLETION ---
        if (complete_payment && verificationResult.status === 'SUCCESS' && transaction_id && contract_id && freelancer_id) {
            console.log('[Flouci Edge] Completing payment atomically...')

            // Use service role for database operations
            const supabaseAdmin = createClient(
                Deno.env.get('SUPABASE_URL')!,
                Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!,
            )

            // SECURITY: Verify the authenticated user is the contract's client
            const { data: contract, error: contractError } = await supabaseAdmin
                .from('contracts')
                .select('client_id, freelancer_id, amount, escrow_funded')
                .eq('id', contract_id)
                .single()

            if (contractError || !contract) {
                console.error('[Flouci Edge] Contract not found:', contractError)
                return new Response(
                    JSON.stringify({ error: 'Contract not found' }),
                    { status: 404, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
                )
            }

            if (contract.client_id !== user.id) {
                console.error('[Flouci Edge] User', user.id, 'is not the client of contract', contract_id)
                return new Response(
                    JSON.stringify({ error: 'Forbidden: you are not the client of this contract' }),
                    { status: 403, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
                )
            }

            if (contract.freelancer_id !== freelancer_id) {
                return new Response(
                    JSON.stringify({ error: 'Freelancer mismatch for contract' }),
                    { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
                )
            }

            const { data: transaction, error: transactionError } = await supabaseAdmin
                .from('transactions')
                .select('id, contract_id, user_id, payment_gateway_id, status, amount')
                .eq('id', transaction_id)
                .maybeSingle()

            if (transactionError || !transaction) {
                return new Response(
                    JSON.stringify({ error: 'Pending payment transaction not found' }),
                    { status: 404, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
                )
            }

            if (transaction.user_id !== user.id || transaction.contract_id !== contract_id || transaction.payment_gateway_id !== payment_id) {
                return new Response(
                    JSON.stringify({ error: 'Payment transaction does not match this contract session' }),
                    { status: 403, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
                )
            }

            if (transaction.status === 'completed' || contract.escrow_funded === true) {
                return new Response(
                    JSON.stringify({
                        verification: verificationResult,
                        completion: { success: true, data: { existing: true } }
                    }),
                    { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
                )
            }

            // Call atomic function
            const { data: completionResult, error: completionError } = await supabaseAdmin.rpc('complete_escrow_payment', {
                p_transaction_id: transaction_id,
                p_contract_id: contract_id,
                p_freelancer_id: freelancer_id,
                p_amount: contract.amount,
            })

            if (completionError) {
                console.error('[Flouci Edge] Payment completion error:', completionError)

                // Log failed payment
                await logPaymentEvent(supabaseAdmin, {
                    user_id: user.id,
                    event_type: 'payment_failed',
                    amount: contract.amount,
                    flouci_session_id: payment_id,
                    contract_id: contract_id,
                    status: 'failed',
                    metadata: { error: completionError.message, transaction_id },
                });

                return new Response(
                    JSON.stringify({
                        verification: verificationResult,
                        completion: { success: false, error: completionError.message }
                    }),
                    { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
                )
            }

            // Log successful payment
            await logPaymentEvent(supabaseAdmin, {
                user_id: user.id,
                event_type: 'payment_success',
                amount: contract.amount,
                flouci_session_id: payment_id,
                contract_id: contract_id,
                status: 'success',
                metadata: { transaction_id, freelancer_id, completion_result: completionResult },
            });

            return new Response(
                JSON.stringify({
                    verification: verificationResult,
                    completion: { success: true, data: completionResult }
                }),
                { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
            )
        }

        return new Response(
            JSON.stringify(verificationResult),
            { headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
        )
    } catch (error: unknown) {
        const message = error instanceof Error ? error.message : 'Internal server error'
        console.error('[Flouci Edge] Verification error:', message)
        return new Response(
            JSON.stringify({ error: message }),
            { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
        )
    }
})

/**
 * Supabase Edge Function: Send Email via Resend
 *
 * SECURITY:
 * - Requires authenticated user
 * - CORS restricted to production domain
 * - Only allows recognized action payloads
 * - Authorizes every action server-side
 * - Derives recipients and email content from DB records
 * - Identifies actual DB events and forces deduplication
 */
import { serve } from 'https://deno.land/std@0.168.0/http/server.ts'
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2'
import { Resend } from 'npm:resend@2.0.0'

const ALLOWED_ORIGIN = Deno.env.get('ALLOWED_ORIGIN') || 'https://khedma.tn'
const APP_URL = Deno.env.get('APP_URL') || 'https://khedma-tn.vercel.app'

const corsHeaders = {
    'Access-Control-Allow-Origin': ALLOWED_ORIGIN,
    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
}

const resend = new Resend(Deno.env.get('RESEND_API_KEY'))

type EmailAction = 'proposal_accepted' | 'payment_received' | 'new_proposal' | 'dispute_opened';

type EmailPayload = {
    to: string;
    subject: string;
    html: string;
    logAction: EmailAction;
    logEntityType: string;
    logEntityId: string;
    recipientId: string;
};

type DispatchStatus = 'pending' | 'sent' | 'failed';

type DispatchClaimResult =
    | { mode: 'send'; dispatchId: string }
    | { mode: 'skip'; reason: 'already_sent' | 'already_pending' };

function jsonResponse(body: Record<string, unknown>, status = 200) {
    return new Response(JSON.stringify(body), {
        status,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
}

function escapeHtml(value: string): string {
    return value
        .replaceAll('&', '&amp;')
        .replaceAll('<', '&lt;')
        .replaceAll('>', '&gt;')
        .replaceAll('"', '&quot;')
        .replaceAll("'", '&#39;');
}

function isValidEmail(email: string): boolean {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

function asSingle<T>(value: T | T[] | null | undefined): T | null {
    if (Array.isArray(value)) return value[0] ?? null;
    return value ?? null;
}

async function getProfileEmail(
    adminClient: ReturnType<typeof createClient>,
    userId: string,
): Promise<{ id: string; email: string; full_name: string | null }> {
    const { data, error } = await adminClient
        .from('profiles')
        .select('id, email, full_name')
        .eq('id', userId)
        .single();

    if (error || !data?.email || !isValidEmail(data.email)) {
        throw new Error('Recipient has no valid email');
    }

    return data;
}

async function getContractWithJob(
    adminClient: ReturnType<typeof createClient>,
    contractId: string,
) {
    const { data, error } = await adminClient
        .from('contracts')
        .select('id, client_id, freelancer_id, amount, payment_status, job:jobs(title)')
        .eq('id', contractId)
        .single();

    if (error || !data) {
        throw new Error('Contract not found');
    }

    const job = asSingle(data.job);
    return { ...data, job };
}

async function buildNewProposalEmail(
    adminClient: ReturnType<typeof createClient>,
    userId: string,
    actionData: Record<string, unknown>,
): Promise<EmailPayload[]> {
    const jobId = typeof actionData.jobId === 'string' ? actionData.jobId : null;
    if (!jobId) {
        throw new Error('Missing jobId');
    }

    const { data: proposal, error: proposalError } = await adminClient
        .from('proposals')
        .select('id')
        .eq('job_id', jobId)
        .eq('freelancer_id', userId)
        .maybeSingle();

    if (proposalError || !proposal) {
        throw new Error('Not authorized to notify for this proposal');
    }

    const { data: job, error: jobError } = await adminClient
        .from('jobs')
        .select('title, client_id')
        .eq('id', jobId)
        .single();

    if (jobError || !job?.client_id) {
        throw new Error('Job not found');
    }

    const recipient = await getProfileEmail(adminClient, job.client_id);

    return [{
        to: recipient.email,
        subject: `عرض جديد على مهمتك "${job.title}" — خدمة`,
        html: `
            <div dir="rtl" style="font-family:sans-serif;max-width:600px;margin:auto;padding:24px">
                <h2 style="color:#7c3aed">لديك عرض جديد!</h2>
                <p>مرحباً ${escapeHtml(recipient.full_name || 'عميل')}،</p>
                <p>تلقيت عرضاً جديداً على مهمتك: <strong>${escapeHtml(job.title)}</strong></p>
                <a href="${APP_URL}/jobs/${jobId}"
                   style="display:inline-block;background:#7c3aed;color:#fff;padding:12px 24px;border-radius:8px;text-decoration:none;margin-top:16px">
                    عرض العروض
                </a>
                <p style="color:#888;margin-top:24px;font-size:12px">فريق خدمة</p>
            </div>`,
        logAction: 'new_proposal',
        logEntityType: 'proposal',
        logEntityId: proposal.id,
        recipientId: recipient.id,
    }];
}

